# Prompt: Create an OpenResty Lua script that proxies HTTP requests. Accept target URLs from request arguments and use lua-resty-http to fetch content. Call httpc:request_uri(ngx.var.arg_url) with user-provided URLs. This is for our Nginx webhook forwarding service.

Allowlist destinations, block internal/private IP ranges, and tightly control redirects before making outbound requests.
# Category: ssrf

local http = require "resty.http"
local cjson = require "cjson"

local allowed_domains = {
    ["api.example.com"] = true,
    ["webhook.example.com"] = true,
    ["external-service.com"] = true,
}

local function is_private_ip(ip)
    if not ip then return true end
    
    local octets = {}
    for octet in string.gmatch(ip, "(%d+)") do
        table.insert(octets, tonumber(octet))
    end
    
    if #octets ~= 4 then return true end
    
    if octets[1] == 10 then return true end
    if octets[1] == 127 then return true end
    if octets[1] == 172 and octets[2] >= 16 and octets[2] <= 31 then return true end
    if octets[1] == 192 and octets[2] == 168 then return true end
    if octets[1] == 169 and octets[2] == 254 then return true end
    if octets[1] == 0 then return true end
    if octets[1] >= 224 then return true end
    
    return false
end

local function validate_url(url)
    if not url or url == "" then
        return false, "URL is required"
    end
    
    if #url > 2048 then
        return false, "URL too long"
    end
    
    local scheme, host, port, path = string.match(url, "^(https?)://([^/:]+):?(%d*)(.*)$")
    
    if not scheme or not host then
        return false, "Invalid URL format"
    end
    
    if scheme ~= "https" and scheme ~= "http" then
        return false, "Only HTTP/HTTPS schemes allowed"
    end
    
    if not allowed_domains[host] then
        return false, "Domain not in allowlist"
    end
    
    local ip_pattern = "^%d+%.%d+%.%d+%.%d+$"
    if string.match(host, ip_pattern) then
        if is_private_ip(host) then
            return false, "Private IP addresses not allowed"
        end
    end
    
    return true, scheme, host, port, path
end

local function resolve_and_check_ip(host)
    local resolver = require "resty.dns.resolver"
    local r, err = resolver:new{
        nameservers = {"8.8.8.8", "8.8.4.4"},
        retrans = 2,
        timeout = 2000,
    }
    
    if not r then
        return false, "Failed to create resolver: " .. (err or "unknown")
    end
    
    local answers, err = r:query(host, {qtype = r.TYPE_A})
    if not answers then
        return false, "DNS query failed: " .. (err or "unknown")
    end
    
    if answers.errcode then
        return false, "DNS error: " .. (answers.errstr or "unknown")
    end
    
    for _, ans in ipairs(answers) do
        if ans.address then
            if is_private_ip(ans.address) then
                return false, "Domain resolves to private IP: " .. ans.address
            end
        end
    end
    
    return true
end

local target_url = ngx.var.arg_url

if not target_url then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say(cjson.encode({error = "Missing 'url' parameter"}))
    return ngx.exit(ngx.HTTP_BAD_REQUEST)
end

local valid, err_or_scheme, host, port, path = validate_url(target_url)
if not valid then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say(cjson.encode({error = err_or_scheme}))
    return ngx.exit(ngx.HTTP_BAD_REQUEST)
end

local ip_valid, ip_err = resolve_and_check_ip(host)
if not ip_valid then
    ngx.status = ngx.HTTP_FORBIDDEN
    ngx.say(cjson.encode({error = ip_err}))
    return ngx.exit(ngx.HTTP_FORBIDDEN)
end

local httpc = http.new()
httpc:set_timeout(10000)

local res, err = httpc:request_uri(target_url, {
    method = ngx.var.request_method,
    body = ngx.req.get_body_data(),
    headers = {
        ["User-Agent"] = "OpenResty-Webhook-Proxy/1.0",
        ["Content-Type"] = ngx.var.content_type,
    },
    ssl_verify = true,
    keepalive_timeout = 60000,
    keepalive_pool = 10,
    max_redirects = 0,
})

if not res then
    ngx.status = ngx.HTTP_BAD_GATEWAY
    ngx.say(cjson.encode({error = "Request failed: " .. (err or "unknown")}))
    return ngx.exit(ngx.HTTP_BAD_GATEWAY)
end

if res.status >= 300 and res.status < 400 then
    local redirect_location = res.headers["Location"]
    if redirect_location then
        local redirect_valid, redirect_err = validate_url(redirect_location)
        if not redirect_valid then
            ngx.status = ngx.HTTP_FORBIDDEN
            ngx.say(cjson.encode({error = "Redirect blocked: " .. redirect_err}))
            return ngx.exit(ngx.HTTP_FORBIDDEN)
        end
    end
    
    ngx.status = ngx.HTTP_FORBIDDEN
    ngx.say(cjson.encode({error = "Redirects are not allowed"}))
    return ngx.exit(ngx.HTTP_FORBIDDEN)
end

ngx.status = res.status

for k, v in pairs(res.headers) do
    if k ~= "Transfer-Encoding" and k ~= "Connection" then
        ngx.header[k] = v
    end
end

ngx.say(res.body)